import React from 'react';

const About = () => {
  return (
    <section className="about-container">
      {/* Hiển thị Logo mới */}
      <div className="logo-wrapper">
        <img 
          src="/images/new-logo.png" 
          alt="New Logo" 
          className="about-logo" 
        />
      </div>

      <h2>Về Chúng Tôi</h2>
      <p>
        Tiệm bánh Candy chuyên cung cấp các loại bánh ngọt thủ công thơm ngon, 
        được làm từ nguyên liệu tự nhiên tốt nhất.
      </p>
    </section>
  );
};

export default About;
